/**
 * Fuentes WOFF embebidas como base64 para la generación de imágenes OG.
 *
 * Por qué embebidas y no leídas con fs: en Vercel, los archivos sueltos NO
 * viajan al bundle de la función (includeFiles resultó poco fiable). Embeberlas
 * como código garantiza que el bundler SIEMPRE las incluya. Se regeneran con
 * scripts/generar-fuentes.mjs si cambian los .woff de api/_fonts/.
 */

const interRegB64 = '';
const interBoldB64 = '';
const monoRegB64 = '';
const monoSemiB64 = '';

const dec = (b64: string): Buffer => Buffer.from(b64, "base64");

export const FUENTES_OG = [
  { name: "Inter", data: dec(interRegB64), weight: 400 as const, style: "normal" as const },
  { name: "Inter", data: dec(interBoldB64), weight: 700 as const, style: "normal" as const },
  { name: "JetBrains Mono", data: dec(monoRegB64), weight: 400 as const, style: "normal" as const },
  { name: "JetBrains Mono", data: dec(monoSemiB64), weight: 600 as const, style: "normal" as const },
];
